import { NativeStackScreenProps } from '@react-navigation/native-stack';
import { Dispatch } from 'redux';
import type { DataObject } from '~/redux/ducks/microInsurances/Models';

import { InvoiceObj } from '../../redux/ducks/invoice';
import { AppReducers } from '../../redux/reducers/Models';
import { TransactionResume } from '../../redux/sagas/invoices/Models/invoice';
import { AuxiliaryScreenRouteParams } from '../../screens/Cards/DetailPhysicalCard/AuxiliaryScreen/Models';
import { NumberCardPhysicalRouteParams } from '../../screens/Cards/DetailPhysicalCard/Models';
import { NumberCardVirtualRecurrentRouteParams } from '../../screens/Cards/DetailVirtualCardRecurrent/Models';
import { EditCardAddressRouteParams } from '../../screens/EditCardAddress/Models';
import { InstructionsToCreatePasswordParams } from '../../screens/InstructionsToCreatePassword/Models';
import { InstructionsToLivenessParams } from '../../screens/InstructionsToLiveness/Models';
import { InvoiceCardParams } from '../../screens/InvoiceCard/Models';
import { LivenessParams } from '../../screens/Liveness/Models';
import { PasswordCardParams } from '../../screens/PasswordCard/Models';
import { ConfirmPasswordCardParams } from '../../screens/PasswordCard/Models/confirmPasswordCard';
import { PayInvoiceParams } from '../../screens/PayInvoice/Options/Models';
import { SimulationResumeParams } from '../../screens/PayInvoice/SimulationResume/Models';
import { BankDetailsFormParams } from '../../screens/PayMethods/Backdrops/BankDetailsForm/Models';
import { PaymentChangeParams } from '../../screens/PayMethods/Backdrops/PaymentChange/Models';
import { PointsTransaction } from '../../redux/ducks/points';

export interface AnalyticsProps {
  analytics: {
    screen_name: string;
    screen_class: string;
    screen_bussines: string;
    screen_info: {
      location_1: string;
      location_2: string;
      location_3: string;
    };
  };
}

export type OptionalAnalyticsProps = Partial<AnalyticsProps> | undefined;

export type PropsFintechCardRoutes = {
  CardUnlock: OptionalAnalyticsProps;
  CardVerificationCode: OptionalAnalyticsProps;
  DetailPhysicalCard: NumberCardPhysicalRouteParams & AnalyticsProps;
  FintechHome?: {
    id?: string;
    shouldShowCancelAdditionalCardSnackBar?: boolean;
  } & OptionalAnalyticsProps;
  SearchActivity: OptionalAnalyticsProps & AnalyticsProps;
  InvoiceCard: InvoiceCardParams & AnalyticsProps;
  Configurations: {
    originScreen?: string;
  } & AnalyticsProps;
  SimulationResume: SimulationResumeParams & AnalyticsProps;
  BlockDuplicateModal: OptionalAnalyticsProps;
  AuxiliaryScreen: AuxiliaryScreenRouteParams & AnalyticsProps;
  EditCardAddressHome: EditCardAddressRouteParams & AnalyticsProps;
  DetailVirtualCardRecurrent: NumberCardVirtualRecurrentRouteParams & AnalyticsProps;
  PayInvoice: PayInvoiceParams & AnalyticsProps;
  InvoicesHistory: OptionalAnalyticsProps;
  PayMethods: OptionalAnalyticsProps;
  Cashback: OptionalAnalyticsProps;
  LearnMoreRewardProgram: OptionalAnalyticsProps;
  SearchCashback: OptionalAnalyticsProps;
  RewardProgramMarketplace: OptionalAnalyticsProps;
  AirlineMilesMarketplace: OptionalAnalyticsProps;
  PasswordCard: PasswordCardParams & AnalyticsProps;
  ConfirmPasswordCard: ConfirmPasswordCardParams & AnalyticsProps;
  InstructionsToLiveness: InstructionsToLivenessParams & AnalyticsProps;
  Liveness: LivenessParams & AnalyticsProps;
  InstructionsToCreatePassword: InstructionsToCreatePasswordParams & AnalyticsProps;
  TagDetail: NumberCardVirtualRecurrentRouteParams & AnalyticsProps;
  FintechBenefits: OptionalAnalyticsProps;
  FaqExemptionEligibility: OptionalAnalyticsProps;
  InvoiceCashbackOnboarding: {
    conversionFactor?: number;
    productCode?: string;
    campaingId?: string;
  } & OptionalAnalyticsProps;
  InvoiceCashbackPoints: {
    conversionFactor?: number;
    productCode?: string;
    campaingId?: string;
  } & OptionalAnalyticsProps;
  InvoiceCashbackSummary: {
    conversionFactor?: number;
    pointsSelected?: number;
    reaisSelected?: number;
    productCode?: string;
    campaingId?: string;
  } & OptionalAnalyticsProps;
  RewardProgram: OptionalAnalyticsProps;
  PointsDetail: {
    transaction: PointsTransaction;
  } & OptionalAnalyticsProps;
  ExtractRewardProgram: OptionalAnalyticsProps;
  InvoiceCardDetails: {
    referanceId: string | null;
    data?: TransactionResume;
    invoice?: InvoiceObj;
    date: number;
  } & AnalyticsProps;
  AddressEditCard: OptionalAnalyticsProps;
  BankDetailsForm: BankDetailsFormParams & OptionalAnalyticsProps;
  PaymentChange: PaymentChangeParams & OptionalAnalyticsProps;
  CardValidation: {
    lastFourNumbers: string;
    onConfirm?: (_number: string) => void;
  } & AnalyticsProps;
  MissingInstructions: OptionalAnalyticsProps;
  CardTracking: {
    account: string;
    cardNumber: string;
  } & OptionalAnalyticsProps;
  EditAddressTrackingCard: OptionalAnalyticsProps;
  AdditionalCardAge?: { isEditing?: boolean } & OptionalAnalyticsProps;
  AdditionalCardInstructions: OptionalAnalyticsProps;
  AdditionalCardConcluded: OptionalAnalyticsProps;
  AdditionalCardName?: { isEditing?: boolean } & OptionalAnalyticsProps;
  EditAddressAdditionalCard: OptionalAnalyticsProps;
  LimitAdditionalCard?: {
    isEditing?: boolean;
    lastFourNumbers?: string;
  } & OptionalAnalyticsProps;
  CheckoutAdditionalCard: OptionalAnalyticsProps;
  MyOrdersRewardProgram: OptionalAnalyticsProps;
};

export type PropsRootStack = {
  Splash: undefined;
  LoginScreen: {
    isLogout: boolean;
  };
  HomeScreen: undefined;
  Home?: {
    screen?: string;
  };
  InvoicesHistory: undefined;
  PlanDetails: { item: DataObject };
  Refuel: { backServices: boolean };
} & PropsFintechCardRoutes;

export type ConnectProps<
  StateT extends (_reducers: AppReducers) => object = () => object,
  DispatchT extends (_dispatch: Dispatch) => object = () => object
> = ReturnType<StateT> & ReturnType<DispatchT>;

export type ScreenProps<
  RouteName extends keyof PropsRootStack,
  StateT extends (_reducers: AppReducers) => object = () => object,
  DispatchT extends (_dispatch: Dispatch) => object = () => object
> = ConnectProps<StateT, DispatchT> & NativeStackScreenProps<PropsRootStack, RouteName>;

