export interface CheckNameEligibilityResponse {
  code: number;
  message: string;
  data: {
    nameIsValid: boolean;
    message?: string;
  };
}

export interface CreateAdditionalCardResponse {
  Cartao: string;
  Conta: string;
  pantoken?: string;
}

export interface CheckNameEligibilityPayload {
  socialName: string;
}

export interface CreateAdditionalCardPayload {
  CPF: string;
  Conta: string;
  Nome: string;
  Limite: string;
}

export type AdditionalCardCallback = (_success: boolean) => void;

export interface AdditionalCardState {
  name: string;
  isLoadingName: boolean;
  isErrorName: boolean;
  errorNameMessage: string;
  birthDate: string;
  limit: string;
  isLoading: boolean;
  isError: boolean;
  errorMessage: string;
}

export interface AdditionalCardActions {
  setName: (_name: string) => void;
  setLoadingName: (_isLoading: boolean) => void;
  setErrorName: (_error: string) => void;
  clearNameError: () => void;
  setBirthDate: (_birthDate: string) => void;
  setLimit: (_limit: string) => void;
  setLoading: (_isLoading: boolean) => void;
  setError: (_error: string) => void;
  clearError: () => void;
  reset: () => void;
}

export interface AdditionalCardServiceContract {
  validateName: (_name: string, _callback?: AdditionalCardCallback) => Promise<void>;
  createAdditionalCard: (_callback?: AdditionalCardCallback) => Promise<void>;
}

export interface UpdateAddressResponse {
  status?: {
    codigoRetorno: number;
    mensagem?: string;
  };
  data?: unknown;
  error?: boolean;
  description?: string;
  salvarResponse?: unknown;
}

export interface AddressValidationPayload {
  PostalCode?: string;
  Street?: string;
  Number?: string;
  Neighborhood?: string;
  State?: string;
  City?: string;
  Complement?: string | null;
  Reference?: string | null;
}

export interface AddressValidationError {
  field: string;
  message: string;
}

export interface AddressValidationResponse {
  code: number;
  message: string;
  data: {
    validated: boolean;
    errors?: AddressValidationError[];
  };
}

export type AddressValidationCallback = (
  _success: boolean,
  _errors?: AddressValidationError[]
) => void;

