     1→import {
     2→  getFuncDevicesName,
     3→  getUserLocation,
     4→  logError,
     5→} from '@semparar/mf-app-user';
     6→import {
     7→  getUUID,
     8→  refreshTokenGlobal,
     9→} from '@semparar/mf-app-user/src/redux/sagas/user/login/functions';
    10→import { AxiosError, AxiosRequestConfig, AxiosResponse } from 'axios';
    11→import jwt_decode from 'jwt-decode';
    12→import { Platform } from 'react-native';
    13→import DeviceInfo from 'react-native-device-info';
    14→import UserAgent from 'react-native-user-agent';
    15→import environment from '~/settings/environment';
    16→
    17→import storage from '~/redux/store/storage';
    18→import api from '../settings/apiFintech';
    19→
    20→api.baseUrl = environment.fintech.api;
    21→api.config = {
    22→  headers: {
    23→    'x-api-key': environment.fintech.apiKeyOld,
    24→    caller: 'sem-parar',
    25→  },
    26→};
    27→
    28→const uriAuthCreditCard = '/auth-token';
    29→const uriRefreshCreditCard = '/token';
    30→
    31→const canceRequest: () => void = () => {
    32→  throw 'Operation canceled because token expired.';
    33→};
    34→
    35→const getIsNotExceptionDomain = ({
    36→  baseUrl,
    37→  url,
    38→}: {
    39→  baseUrl?: string;
    40→  url?: string;
    41→}) => {
    42→  const uri = url?.includes('https') ? url : `${baseUrl ?? ''}${url ?? ''}`;
    43→  return !environment?.fintech?.exceptionKeycloakDomains?.find?.(
    44→    (domain: string) => uri?.includes(domain),
    45→  );
    46→};
    47→
    48→const getIsSendOriginToken = ({
    49→  baseUrl,
    50→  url,
    51→}: {
    52→  baseUrl?: string;
    53→  url?: string;
    54→}) => {
    55→  const uri = url?.includes('https') ? url : `${baseUrl ?? ''}${url ?? ''}`;
    56→  return !!environment?.fintech?.sendOriginTokenDomains?.find?.(
    57→    (domain: string) => uri?.includes(domain),
    58→  );
    59→};
    60→
    61→export const forcedRefreshCreditCard: (
    62→  _config: AxiosRequestConfig,
    63→) => Promise<AxiosRequestConfig> = async (config: AxiosRequestConfig) => {
    64→  const accessTokenApp = await storage.getItem('accessToken');
    65→  const refreshTokenApp = await storage.getItem('refreshToken');
    66→  const accessToken = await storage.getItem('accessTokenCreditCard');
    67→  const refreshToken = await storage.getItem('refreshTokenCreditCard');
    68→
    69→  if (
    70→    accessTokenApp &&
    71→    !config.url?.includes(uriRefreshCreditCard) &&
    72→    !config.url?.includes(uriAuthCreditCard)
    73→  ) {
    74→    const { exp: expApp }: { exp: number } = jwt_decode(accessTokenApp);
    75→    if (expApp) {
    76→      let date = new Date(expApp * 1000);
    77→      let now = new Date();
    78→      let diff = date.getTime() - now.getTime();
    79→      let minutesDiff = diff / (1000 * 60);
    80→
    81→      if (minutesDiff < 2) {
    82→        await refreshTokenGlobal(refreshTokenApp);
    83→      }
    84→      if (
    85→        getIsNotExceptionDomain({
    86→          baseUrl: api.baseUrl,
    87→          url: config?.url,
    88→        })
    89→      ) {
    90→        let jwt;
    91→        try {
    92→          if (refreshToken) jwt = jwt_decode(refreshToken ?? '');
    93→        } catch (e) {}
    94→
    95→        date = new Date((jwt?.exp ?? 0) * 1000);
    96→        now = new Date();
    97→        diff = date.getTime() - now.getTime();
    98→        minutesDiff = diff / (1000 * 60);
    99→
   100→        if (minutesDiff < 1) {
   101→          const accessTokenAppAuth = await storage.getItem('accessToken');
   102→
   103→          await api
   104→            .get(`${environment.fintech.keycloakApi}${uriAuthCreditCard}`, {
   105→              headers: {
   106→                accesstoken: accessTokenAppAuth,
   107→                'x-api-key': environment.fintech.apiKeyOld,
   108→              },
   109→            })
   110→            .then(async resp => {
   111→              const data = resp?.data;
   112→
   113→              if (data?.data?.token) {
   114→                await storage.setItem(
   115→                  'accessTokenCreditCard',
   116→                  data?.data?.token,
   117→                );
   118→                await storage.setItem(
   119→                  'refreshTokenCreditCard',
   120→                  data?.data?.refreshToken,
   121→                );
   122→              }
   123→            });
   124→        } else {
   125→          try {
   126→            if (accessToken) jwt = jwt_decode(accessToken ?? '');
   127→          } catch (e) {}
   128→
   129→          date = new Date((jwt?.exp ?? 0) * 1000);
   130→          now = new Date();
   131→          diff = date.getTime() - now.getTime();
   132→          minutesDiff = diff / (1000 * 60);
   133→
   134→          if (minutesDiff < 1) {
   135→            await api
   136→              .get(
   137→                `${environment.fintech.keycloakApi}${uriRefreshCreditCard}`,
   138→                {
   139→                  headers: {
   140→                    refresh_token: refreshToken,
   141→                    'x-api-key': environment.fintech.apiKeyOld,
   142→                  },
   143→                },
   144→              )
   145→              .then(async (resp: AxiosResponse) => {
   146→                if (resp?.data?.data?.token) {
   147→                  await storage.setItem(
   148→                    'accessTokenCreditCard',
   149→                    resp?.data?.data?.token,
   150→                  );
   151→                } else {
   152→                  canceRequest();
   153→                }
   154→              })
   155→              .catch((_error: AxiosError) => {
   156→                canceRequest();
   157→              });
   158→          }
   159→        }
   160→      }
   161→    }
   162→
   163→    if (
   164→      getIsNotExceptionDomain({
   165→        baseUrl: api.baseUrl,
   166→        url: config?.url,
   167→      })
   168→    ) {
   169→      const accessTokenUpdate = await storage.getItem('accessTokenCreditCard');
   170→      config.headers['x-access-token'] = `${accessTokenUpdate}`;
   171→    }
   172→  }
   173→
   174→  if (accessTokenApp) {
   175→    const {
   176→      NRC,
   177→    }: {
   178→      NRC: string;
   179→    } = jwt_decode(accessTokenApp);
   180→    config.headers['x-client-code'] = `${NRC}`;
   181→    config.headers.codigocliente = `${NRC}`;
   182→  }
   183→
   184→  const userAgent =
   185→    Platform.OS === 'android'
   186→      ? `${DeviceInfo.getApplicationName()}/${DeviceInfo.getVersion()}.${DeviceInfo.getBuildNumber()} ${UserAgent.getUserAgent()
   187→          .split(' ')
   188→          .slice(1)
   189→          .join(' ')}`
   190→      : UserAgent.getUserAgent();
   191→
   192→  config.headers['User-Agent'] = userAgent;
   193→
   194→  const location = await getUserLocation();
   195→
   196→  config.headers.devicename = await getFuncDevicesName();
   197→  config.headers.lat = String(location[0]);
   198→  config.headers.long = String(location[1]);
   199→
   200→  const uuid = await getUUID();
   201→
   202→  config.headers['x-uuid'] = uuid;
   203→  config.headers.uuid = uuid;
   204→
   205→  if (
   206→    getIsSendOriginToken({
   207→      baseUrl: api?.baseUrl,
   208→      url: config?.url,
   209→    })
   210→  ) {
   211→    const accessTokenAppUpdate = await storage.getItem('accessToken');
   212→    if (accessTokenApp) {
   213→      config.headers.accesstoken = `${accessTokenAppUpdate}`;
   214→      config.headers['x-access-token'] = `${accessTokenAppUpdate}`;
   215→      config.headers.uuid = uuid;
   216→    }
   217→  }
   218→
   219→  return config;
   220→};
   221→
   222→api.interceptors.request.use(
   223→  async (config: AxiosRequestConfig): Promise<void> => {
   224→    try {
   225→      const updatedConfig = await forcedRefreshCreditCard(config);
   226→
   227→      return updatedConfig;
   228→    } catch (error) {
   229→      logError(error);
   230→      return Promise.reject(error);
   231→    }
   232→  },
   233→);
   234→
   235→api.interceptors.response.use(async (response: any): Promise<any> => {
   236→  try {
   237→    return response;
   238→  } catch (error: any) {
   239→    logError(error);
   240→    return Promise.reject(error);
   241→  }
   242→});
   243→
   244→export default api;
