import {
  getFuncDevicesName,
  getUserLocation,
  logError,
} from '@semparar/mf-app-user';
import {
  getUUID,
  refreshTokenGlobal,
} from '@semparar/mf-app-user/src/redux/sagas/user/login/functions';
import { AxiosError, AxiosRequestConfig, AxiosResponse } from 'axios';
import jwt_decode from 'jwt-decode';
import { Platform } from 'react-native';
import DeviceInfo from 'react-native-device-info';
import UserAgent from 'react-native-user-agent';
import environment from '~/settings/environment';

import storage from '~/redux/store/storage';
import api from '../settings/apiFintech';

api.baseUrl = environment.fintech.api;
api.config = {
  headers: {
    'x-api-key': environment.fintech.apiKeyOld,
    caller: 'sem-parar',
  },
};

const uriAuthCreditCard = '/auth-token';
const uriRefreshCreditCard = '/token';

const canceRequest: () => void = () => {
  throw 'Operation canceled because token expired.';
};

const getIsNotExceptionDomain = ({
  baseUrl,
  url,
}: {
  baseUrl?: string;
  url?: string;
}) => {
  const uri = url?.includes('https') ? url : `${baseUrl ?? ''}${url ?? ''}`;
  return !environment?.fintech?.exceptionKeycloakDomains?.find?.(
    (domain: string) => uri?.includes(domain),
  );
};

const getIsSendOriginToken = ({
  baseUrl,
  url,
}: {
  baseUrl?: string;
  url?: string;
}) => {
  const uri = url?.includes('https') ? url : `${baseUrl ?? ''}${url ?? ''}`;
  return !!environment?.fintech?.sendOriginTokenDomains?.find?.(
    (domain: string) => uri?.includes(domain),
  );
};

export const forcedRefreshCreditCard: (
  _config: AxiosRequestConfig,
) => Promise<AxiosRequestConfig> = async (config: AxiosRequestConfig) => {
  const accessTokenApp = await storage.getItem('accessToken');
  const refreshTokenApp = await storage.getItem('refreshToken');
  const accessToken = await storage.getItem('accessTokenCreditCard');
  const refreshToken = await storage.getItem('refreshTokenCreditCard');

  if (
    accessTokenApp &&
    !config.url?.includes(uriRefreshCreditCard) &&
    !config.url?.includes(uriAuthCreditCard)
  ) {
    const { exp: expApp }: { exp: number } = jwt_decode(accessTokenApp);
    if (expApp) {
      let date = new Date(expApp * 1000);
      let now = new Date();
      let diff = date.getTime() - now.getTime();
      let minutesDiff = diff / (1000 * 60);

      if (minutesDiff < 2) {
        await refreshTokenGlobal(refreshTokenApp);
      }
      if (
        getIsNotExceptionDomain({
          baseUrl: api.baseUrl,
          url: config?.url,
        })
      ) {
        let jwt;
        try {
          if (refreshToken) jwt = jwt_decode(refreshToken ?? '');
        } catch (e) {}

        date = new Date((jwt?.exp ?? 0) * 1000);
        now = new Date();
        diff = date.getTime() - now.getTime();
        minutesDiff = diff / (1000 * 60);

        if (minutesDiff < 1) {
          const accessTokenAppAuth = await storage.getItem('accessToken');

          await api
            .get(`${environment.fintech.keycloakApi}${uriAuthCreditCard}`, {
              headers: {
                accesstoken: accessTokenAppAuth,
                'x-api-key': environment.fintech.apiKeyOld,
              },
            })
            .then(async resp => {
              const data = resp?.data;

              if (data?.data?.token) {
                await storage.setItem(
                  'accessTokenCreditCard',
                  data?.data?.token,
                );
                await storage.setItem(
                  'refreshTokenCreditCard',
                  data?.data?.refreshToken,
                );
              }
            });
        } else {
          try {
            if (accessToken) jwt = jwt_decode(accessToken ?? '');
          } catch (e) {}

          date = new Date((jwt?.exp ?? 0) * 1000);
          now = new Date();
          diff = date.getTime() - now.getTime();
          minutesDiff = diff / (1000 * 60);

          if (minutesDiff < 1) {
            await api
              .get(
                `${environment.fintech.keycloakApi}${uriRefreshCreditCard}`,
                {
                  headers: {
                    refresh_token: refreshToken,
                    'x-api-key': environment.fintech.apiKeyOld,
                  },
                },
              )
              .then(async (resp: AxiosResponse) => {
                if (resp?.data?.data?.token) {
                  await storage.setItem(
                    'accessTokenCreditCard',
                    resp?.data?.data?.token,
                  );
                } else {
                  canceRequest();
                }
              })
              .catch((_error: AxiosError) => {
                canceRequest();
              });
          }
        }
      }
    }

    if (
      getIsNotExceptionDomain({
        baseUrl: api.baseUrl,
        url: config?.url,
      })
    ) {
      const accessTokenUpdate = await storage.getItem('accessTokenCreditCard');
      config.headers['x-access-token'] = `${accessTokenUpdate}`;
    }
  }

  if (accessTokenApp) {
    const {
      NRC,
    }: {
      NRC: string;
    } = jwt_decode(accessTokenApp);
    config.headers['x-client-code'] = `${NRC}`;
    config.headers.codigocliente = `${NRC}`;
  }

  const userAgent =
    Platform.OS === 'android'
      ? `${DeviceInfo.getApplicationName()}/${DeviceInfo.getVersion()}.${DeviceInfo.getBuildNumber()} ${UserAgent.getUserAgent()
          .split(' ')
          .slice(1)
          .join(' ')}`
      : UserAgent.getUserAgent();

  config.headers['User-Agent'] = userAgent;

  const location = await getUserLocation();

  config.headers.devicename = await getFuncDevicesName();
  config.headers.lat = String(location[0]);
  config.headers.long = String(location[1]);

  const uuid = await getUUID();

  config.headers['x-uuid'] = uuid;
  config.headers.uuid = uuid;

  if (
    getIsSendOriginToken({
      baseUrl: api?.baseUrl,
      url: config?.url,
    })
  ) {
    const accessTokenAppUpdate = await storage.getItem('accessToken');
    if (accessTokenApp) {
      config.headers.accesstoken = `${accessTokenAppUpdate}`;
      config.headers['x-access-token'] = `${accessTokenAppUpdate}`;
      config.headers.uuid = uuid;
    }
  }

  return config;
};

api.interceptors.request.use(
  async (config: AxiosRequestConfig): Promise<void> => {
    try {
      const updatedConfig = await forcedRefreshCreditCard(config);

      return updatedConfig;
    } catch (error) {
      logError(error);
      return Promise.reject(error);
    }
  },
);

api.interceptors.response.use(async (response: any): Promise<any> => {
  try {
    return response;
  } catch (error: any) {
    logError(error);
    return Promise.reject(error);
  }
});

export default api;

