   308→          method: method,
   309→          url: formattedUri,
   310→          headers: params?.headers ?? {},
   311→          data: formattedBody ?? {},
   312→        };
   313→        logRequest(axiosRequestConfig);
   314→        const requestData = await NativeModules.API.fetch(
   315→          method,
   316→          formattedUri,
   317→          JSON.stringify(params?.headers ?? {}),
   318→          JSON.stringify(formattedBody ?? {}),
   319→          Platform.OS === 'android'
   320→            ? environment?.fintech?.certNameAndroid
   321→            : environment?.fintech?.certNameIos,
   322→        );
   323→        if (requestData?.status >= 200 && requestData?.status < 300) {
   324→          logResponse(requestData);
   325→        } else {
   326→          logError(requestData);
   327→        }
   328→        const formattedRequestData =
   329→          Platform.OS === 'android' ? JSON.parse(requestData) : requestData;
   330→        if (__DEV__) {
   331→          Reactotron.display({
   332→            name: 'API',
   333→            preview: formattedUri,
   334→            value: {
   335→              ...params,
   336→              url: formattedUri,
   337→              method,
   338→              request: formattedBody ?? {},
   339→              response: formattedRequestData?.data,
   340→              curl: this.getCurl(
   341→                method,
   342→                formattedUri,
   343→                params?.headers,
   344→                formattedBody,
   345→              ),
   346→            },
   347→            important: formattedRequestData?.status > 210,
   348→          });
   349→        }
   350→
   351→        if (formattedRequestData?.status < 210) {
   352→          if (
   353→            isEnabledCrypto &&
   354→            formattedRequestData?.data?.code === 0
   355→          ) {
   356→            formattedRequestData.data.data =
   357→            this.decryptData(
   358→              formattedRequestData?.data?.data,
   359→            );
   360→
   361→            if (__DEV__) {
   362→              Reactotron.display({
   363→                name: 'API_DECRYPT',
   364→                preview: formattedUri,
   365→                value: {
   366→                  ...params,
   367→                  url: formattedUri,
   368→                  method,
   369→                  request: formattedBody ?? {},
   370→                  response: formattedRequestData?.data,
   371→                  curl: this.getCurl(
   372→                    method,
   373→                    formattedUri,
   374→                    params?.headers,
   375→                    formattedBody,
   376→                  ),
   377→                },
   378→                important: formattedRequestData?.status > 210,
   379→              });
   380→            }
   381→          }
   382→          resolve(formattedRequestData);
   383→        } else {
   384→          reject(formattedRequestData);
   385→        }
   386→      } catch (error) {
   387→        logError(error);
   388→        reject(error);
   389→      }
   390→    });
   391→  },
   392→  async request(method, uri, params = {}, body = {}) {
   393→    const headers = Object.assign(
   394→      api?.config?.headers ?? {},
   395→      params?.headers ?? {},
   396→    );
   397→
   398→    const config = { ...api.config, ...params, url: uri, headers };
   399→
   400→    for (const handler of api.interceptors.request.handlers) {
   401→      await handler.call(api, config);
   402→    }
   403→
   404→    try {
   405→      let formattedUri = uri;
   406→      if (Object.values(params?.params ?? {}).length > 0) {
   407→        Object.keys(params?.params).forEach(item => {
   408→          const newParam = `${item}=${params?.params?.[item]}`;
   409→          if (!formattedUri?.includes('?')) {
   410→            formattedUri = `${formattedUri}?${newParam}`;
   411→          } else {
   412→            formattedUri = `${formattedUri}&${newParam}`;
   413→          }
   414→        });
   415→      }
   416→      config.url = formattedUri;
   417→
   418→      const response = await api.fetch(method, config, body);
   419→
   420→      for (const handler of api.interceptors.response.handlers) {
   421→        await handler.call(api, response);
   422→      }
   423→
   424→      return response;
   425→    } catch (error) {
   426→      throw error;
   427→    }
   428→  },
   429→  async get(uri, params) {
   430→    return api.request('GET', uri, params);
   431→  },
   432→  async post(uri, body, params) {
   433→    return api.request('POST', uri, params, body);
   434→  },
   435→  async put(uri, body, params) {
   436→    return api.request('PUT', uri, params, body);
   437→  },
   438→};
   439→
   440→export default api;
