import CryptoES from 'crypto-es';
import { NativeModules, Platform } from 'react-native';
import Reactotron from 'reactotron-react-native';
import forge from 'node-forge';
import environment from '~/settings/environment';
import { logRequest, logResponse, logError} from '@semparar/mf-app-user';

interface ApiResponse {
  status: number;
  data: any;
}

interface Params {
  [key: string]: string;
}

interface Headers {
  [key: string]: string;
}

interface Config {
  params: Params;
  headers: Headers;
  url: string;
}

type RequestInterceptor = (_params: {} | Config) => Promise<void>;
type ResponseInterceptor = (_response: ApiResponse) => Promise<ApiResponse>;

interface Api {
  getCurl(
    _method: string,
    _formattedUri: string,
    _headers: Record<string, string> | undefined,
    _formattedBody: object | undefined,
  ): string;
  getValidateKey(): string;
  getIsNotExceptionValidateTokenDomain(_url: string): boolean;
  getIsNotExceptionRsaDomain(_url: string): boolean;
  encryptRSA(_hmacNodeForge: string): string;
  createHmac(_payloadEncrypted: string): string;
  encryptAES(_data: string, _isTsIso?: boolean): string;
  getEncrypt(
    _method: string,
    _body: object | undefined,
  ): {
    'x-hmac-hash': string;
    'x-ts-iso': string;
  };
  calculateChecksum(_partialUuid: string): string;
  generateSegment(_length: number): string;
  getIsNotExceptionPayloadDomain(_formattedUri: string): boolean;
  decryptData(_data: string): object;
  encryptData(_body?: object): string;
  baseUrl: string;
  config: Config | {};
  interceptors: {
    request: {
      handlers: RequestInterceptor[];
      use(_handler: RequestInterceptor): void;
    };
    response: {
      handlers: ResponseInterceptor[];
      use(_handler: ResponseInterceptor): void;
    };
  };
  fetch(
    _method: string,
    _params: {} | Config,
    _body?: object,
  ): Promise<ApiResponse>;
  request(
    _method: string,
    _uri: string,
    _params?: {} | Config,
    _body?: object,
  ): Promise<ApiResponse>;
  get(_uri: string, _params?: {} | Config): Promise<ApiResponse>;
  post(_uri: string, _body?: object, _params?: {} | Config): Promise<ApiResponse>;
  put(_uri: string, _body?: object, _params?: {} | Config): Promise<ApiResponse>;
}

const api: Api = {
  baseUrl: '',
  config: {},
  interceptors: {
    request: {
      handlers: [],
      use(handler) {
        this.handlers.push(handler);
      },
    },
    response: {
      handlers: [],
      use(handler) {
        this.handlers.push(handler);
      },
    },
  },
  getCurl(
    method: 'GET' | 'POST' | 'PUT' | 'DELETE',
    formattedUrl: string,
    headers?: Record<string, string>,
    data?: object,
  ) {
    let curlCommand = `curl --location "${formattedUrl}"`;

    if (headers) {
      for (const [key, value] of Object.entries(headers)) {
        curlCommand += ` --header "${key}: ${value}"`;
      }
    }

    if (method !== 'GET' && data) {
      curlCommand += ` --header "content-type: application/json"`;
      curlCommand += ` --data '${JSON.stringify(data)}'`;
    }

    return curlCommand.trim();
  },
  createHmac(dataEncrypted) {
    const hmac = forge.hmac.create();
    hmac.start('sha256', environment.fintech.secretRsa);
    hmac.update(dataEncrypted);
    const hmacNodeForge = hmac.digest().toHex();
    return hmacNodeForge;
  },
  encryptRSA(data) {
    const msg = forge.pem.decode(environment.fintech.publicRsa)[0];
    const obj = forge.asn1.fromDer(msg.body);
    const publicKey = forge.pki.publicKeyFromAsn1(obj);
    const encrypted = publicKey.encrypt(data, 'RSA-OAEP');
    return forge.util.encode64(encrypted);
  },
  encryptAES(data, isTsIso = false) {
    const secret = isTsIso
      ? environment.fintech.cryptoKey
      : environment.fintech.secretRsa;
    const key = CryptoES.enc.Hex.parse(secret.substring(0, 32));
    const iv = CryptoES.enc.Hex.parse(secret.substring(32, 48));
    const encrypted = CryptoES.AES.encrypt(data, key, {
      iv,
      mode: CryptoES.mode.CBC,
      padding: CryptoES.pad.Pkcs7,
    });
    const encrypt = encrypted.toString();
    return encrypt;
  },
  getEncrypt(method, body) {
    const tsISO = new Date().toISOString();

    let payloadString;
    if (method === 'GET') {
      payloadString = JSON.stringify({
        'x-ts-iso': tsISO,
        'x-api-key': environment.fintech.apiKeyOld,
      });
    } else {
      const formattedBody = JSON.parse(JSON.stringify(body));
      if (formattedBody?.imagem) delete formattedBody.imagem;
      if (formattedBody?.Base64) delete formattedBody.Base64;
      if (formattedBody?.OnboardingInfo?.Ocr)
        formattedBody.OnboardingInfo.Ocr = (
          formattedBody.OnboardingInfo.Ocr as { TipoDocumento: string }[]
        ).map(({ TipoDocumento }) => ({ TipoDocumento }));
      if (formattedBody?.OnboardingInfo?.Liveness?.Base64)
        delete formattedBody.OnboardingInfo.Liveness.Base64;
      payloadString = JSON.stringify(formattedBody);
      if (__DEV__) {
        Reactotron.display({
          name: 'HMAC_PAYLOAD',
          preview: method,
          value: formattedBody,
        });
      }
    }

    const payloadEncrypted = this.encryptAES(payloadString);

    const encryptIso = this.encryptAES(tsISO.toString(), true);

    const hmacNodeForge = this.createHmac(payloadEncrypted);

    const encryptedHMACrsa = this.encryptRSA(hmacNodeForge);

    return {
      'x-hmac-hash': `${payloadEncrypted}|${encryptedHMACrsa}`,
      'x-ts-iso': encryptIso,
    };
  },
  encryptData(dataToEncrypt) {
    const secretKey = environment.fintech.cryptoKey;
    const key = CryptoES.enc.Hex.parse(secretKey.substring(0, 32));
    const iv = CryptoES.enc.Hex.parse(secretKey.substring(32, 48));
    const encrypted = CryptoES.AES.encrypt(JSON.stringify(dataToEncrypt), key, {
      iv,
      mode: CryptoES.mode.CBC,
      padding: CryptoES.pad.Pkcs7,
    });
    const encrypt = encrypted.toString();
    return encrypt;
  },
  decryptData(dataToDecrypt) {
    if (!dataToDecrypt) return null;
    const secretKey = environment.fintech.decryptKey;
    const key = CryptoES.enc.Hex.parse(secretKey.substring(0, 32));
    const iv = CryptoES.enc.Hex.parse(secretKey.substring(32, 48));
    const decrypted = CryptoES.AES.decrypt(dataToDecrypt, key, {
      iv,
      mode: CryptoES.mode.CBC,
      padding: CryptoES.pad.Pkcs7,
    });
    const decrypt = decrypted.toString(CryptoES.enc.Utf8);

    return JSON.parse(decrypt);
  },
  getIsNotExceptionPayloadDomain(uri) {
    return !environment?.fintech?.exceptionCryptoDomains?.find?.(domain =>
      uri?.includes(domain),
    );
  },
  getIsNotExceptionRsaDomain(uri) {
    return !environment?.fintech?.exceptionRsaDomains?.find?.(domain =>
      uri?.includes(domain),
    );
  },
  getIsNotExceptionValidateTokenDomain(uri) {
    return !environment?.fintech?.exceptionValidateTokenDomains?.find?.(
      domain => uri?.includes(domain),
    );
  },
  generateSegment(length) {
    const characters = '0123456789abcdef';
    let segment = '';
    for (let i = 0; i < length; i++) {
      segment += characters.charAt(
        Math.floor(Math.random() * characters.length),
      );
    }
    return segment;
  },
  calculateChecksum(uuid) {
    let sum = 0;
    const cleanedUuid = uuid.replace(/-/g, '');
    for (let i = 0; i < cleanedUuid.length; i++) {
      sum += parseInt(cleanedUuid[i], 16);
    }
    return (sum % 65536).toString(16).padStart(4, '0');
  },
  getValidateKey() {
    if (typeof BigInt === 'undefined') {
      global.BigInt = require('big-integer');
    }
    const hrTime = BigInt(Date.now() * 1e6);
    let timestamp = hrTime.toString(16);
    timestamp = timestamp.padStart(16, '0').substring(0, 16);
    const random1 = this.generateSegment(4);
    const random2 = this.generateSegment(4);
    const random3 = this.generateSegment(4);
    const random4 = this.generateSegment(12);
    const partialUuid = `${timestamp}-${random1}-${random2}-${random3}-${random4}`;
    const checksum = this.calculateChecksum(partialUuid);
    return `${partialUuid}-${checksum}`;
  },
  async fetch(method, params, body) {
    return new Promise(async (resolve, reject) => {
      try {
        const formattedUri = params?.url?.includes('http')
          ? params?.url
          : api.baseUrl + params?.url;
        const isEnabledCrypto =
          environment?.fintech?.enabledCrypto &&
          this.getIsNotExceptionPayloadDomain(formattedUri);
        let formattedBody = body;
        if (isEnabledCrypto && Object.keys(body ?? {}).length !== 0) {
          if (__DEV__) {
            Reactotron.display({
              name: 'API_ENCRYPT',
              preview: formattedUri,
              value: body,
            });
          }

          formattedBody = {
            data: this.encryptData(body),
          };
        }
        if (
          environment?.fintech?.enabledRsa &&
          this.getIsNotExceptionRsaDomain(formattedUri)
        ) {
          const headers = this.getEncrypt(method, body);
          params.headers = {
            ...params?.headers,
            ...headers,
          };
        }
        if (
          environment?.fintech?.enabledValidateToken &&
          this.getIsNotExceptionValidateTokenDomain(formattedUri)
        ) {
          params.headers = {
            ...params?.headers,
            'x-validate-token': this.getValidateKey(),
          };
        }
        const axiosRequestConfig: AxiosRequestConfig = {
          method: method,
          url: formattedUri,
          headers: params?.headers ?? {},
          data: formattedBody ?? {},
        };
        logRequest(axiosRequestConfig);
        const requestData = await NativeModules.API.fetch(
          method,
          formattedUri,
          JSON.stringify(params?.headers ?? {}),
          JSON.stringify(formattedBody ?? {}),
          Platform.OS === 'android'
            ? environment?.fintech?.certNameAndroid
            : environment?.fintech?.certNameIos,
        );
        if (requestData?.status >= 200 && requestData?.status < 300) {
          logResponse(requestData);
        } else {
          logError(requestData);
        }
        const formattedRequestData =
          Platform.OS === 'android' ? JSON.parse(requestData) : requestData;
        if (__DEV__) {
          Reactotron.display({
            name: 'API',
            preview: formattedUri,
            value: {
              ...params,
              url: formattedUri,
              method,
              request: formattedBody ?? {},
              response: formattedRequestData?.data,
              curl: this.getCurl(
                method,
                formattedUri,
                params?.headers,
                formattedBody,
              ),
            },
            important: formattedRequestData?.status > 210,
          });
        }

        if (formattedRequestData?.status < 210) {
          if (
            isEnabledCrypto &&
            formattedRequestData?.data?.code === 0
          ) {
            formattedRequestData.data.data =
            this.decryptData(
              formattedRequestData?.data?.data,
            );

            if (__DEV__) {
              Reactotron.display({
                name: 'API_DECRYPT',
                preview: formattedUri,
                value: {
                  ...params,
                  url: formattedUri,
                  method,
                  request: formattedBody ?? {},
                  response: formattedRequestData?.data,
                  curl: this.getCurl(
                    method,
                    formattedUri,
                    params?.headers,
                    formattedBody,
                  ),
                },
                important: formattedRequestData?.status > 210,
              });
            }
          }
          resolve(formattedRequestData);
        } else {
          reject(formattedRequestData);
        }
      } catch (error) {
        logError(error);
        reject(error);
      }
    });
  },
  async request(method, uri, params = {}, body = {}) {
    const headers = Object.assign(
      api?.config?.headers ?? {},
      params?.headers ?? {},
    );

    const config = { ...api.config, ...params, url: uri, headers };

    for (const handler of api.interceptors.request.handlers) {
      await handler.call(api, config);
    }

    try {
      let formattedUri = uri;
      if (Object.values(params?.params ?? {}).length > 0) {
        Object.keys(params?.params).forEach(item => {
          const newParam = `${item}=${params?.params?.[item]}`;
          if (!formattedUri?.includes('?')) {
            formattedUri = `${formattedUri}?${newParam}`;
          } else {
            formattedUri = `${formattedUri}&${newParam}`;
          }
        });
      }
      config.url = formattedUri;

      const response = await api.fetch(method, config, body);

      for (const handler of api.interceptors.response.handlers) {
        await handler.call(api, response);
      }

      return response;
    } catch (error) {
      throw error;
    }
  },
  async get(uri, params) {
    return api.request('GET', uri, params);
  },
  async post(uri, body, params) {
    return api.request('POST', uri, params, body);
  },
  async put(uri, body, params) {
    return api.request('PUT', uri, params, body);
  },
};

export default api;

