     1→import { PropsItemsTransactions } from '@semparar/design-system-app/src/atomic/fintech/TransactionsList/Models';
     2→import { PropsIconsNameCore } from '@semparar/design-system-app/src/styles/Models/type.icon';
     3→import moment from 'moment';
     4→
     5→import { CustomTransactionsData } from '../atomic/organisms/CashbackCellDropdown/Models';
     6→import { BankSPLus, RawBanks } from '../redux/ducks/dacc/automaticDebt';
     7→import { InvoiceFintechItem } from '../redux/ducks/invoices';
     8→import { ActivityResponseData } from '../redux/ducks/recentActivities';
     9→import { cashbackListVariants } from '../redux/sagas/cashback/data';
    10→import { invoiceCardData } from '../screens/InvoiceCard/data';
    11→import { PayInvoiceParams } from '../screens/PayInvoice/Options/Models';
    12→import { ParamsPaymentData } from '../screens/PayMethods/Backdrops/PaymentChange/Models';
    13→import { moment as customMoment } from '../services/moment';
    14→import theme from '../styles/theme';
    15→
    16→type CurrencyValue = number | undefined | string;
    17→
    18→type CashBackTransactions = PropsItemsTransactions & {
    19→  percentage: number;
    20→  cashback: string;
    21→  resgate: boolean;
    22→};
    23→
    24→export const formatToCurrency = (fullValue: CurrencyValue): string => {
    25→  if (typeof fullValue === 'undefined') return `R$ 0,00`;
    26→
    27→  const [value, cents] = String(fullValue).replace('-', '').split('.');
    28→
    29→  const formattedCents = cents ? cents.padEnd(2, '0') : '00';
    30→  let formattedValue = '';
    31→
    32→  for (let i = 0; i < value.length; i += 1) {
    33→    const currentDigit = value[value.length - 1 - i];
    34→
    35→    if (i > 0 && i % 3 === 0) {
    36→      formattedValue = `${currentDigit}.${formattedValue}`;
    37→    } else {
    38→      formattedValue = `${currentDigit}${formattedValue}`;
    39→    }
    40→  }
    41→
    42→  return `R$ ${Number(fullValue) >= 0 ? '' : '-'}${formattedValue},${formattedCents[0]}${
    43→    formattedCents[1]
    44→  }`;
    45→};
    46→
    47→export const formatToNumericCurrency = (fullValue: CurrencyValue, decimalPlaces = 2): string => {
    48→  if (typeof fullValue === 'undefined' || fullValue === '0')
    49→    return `0,${'0'.repeat(decimalPlaces)}`;
    50→
    51→  const [value, cents] = String(fullValue).replace('-', '').split('.');
    52→
    53→  const formattedCents = cents ? cents.padEnd(decimalPlaces, '0') : '0'.repeat(decimalPlaces);
    54→  let formattedValue = '';
    55→
    56→  for (let i = 0; i < value.length; i += 1) {
    57→    const currentDigit = value[value.length - 1 - i];
    58→
    59→    if (i > 0 && i % 3 === 0) {
    60→      formattedValue = `${currentDigit}.${formattedValue}`;
    61→    } else {
    62→      formattedValue = `${currentDigit}${formattedValue}`;
    63→    }
    64→  }
    65→
    66→  return `${formattedValue},${formattedCents.slice(0, decimalPlaces)}`;
    67→};
    68→
    69→export const formatToInternationalCurrency = (
    70→  moneyType: string,
    71→  fullValue: number | undefined | string
    72→): string => {
    73→  if (typeof fullValue === 'undefined') return `${moneyType} 0,00`;
    74→
    75→  const [value, cents] = String(fullValue).replace('-', '').split(',');
    76→
    77→  const formattedCents = cents ? cents.padEnd(2, '0') : '00';
    78→  let formattedValue = '';
    79→
    80→  for (let i = 0; i < value.length; i += 1) {
    81→    const currentDigit = value[value.length - 1 - i];
    82→
    83→    if (i > 0 && i % 3 === 0) {
    84→      formattedValue = `${currentDigit} ${formattedValue}`;
    85→    } else {
    86→      formattedValue = `${currentDigit}${formattedValue}`;
    87→    }
    88→  }
    89→
    90→  return `${moneyType} ${Number(fullValue) >= 0 ? '' : '-'}${formattedValue},${formattedCents}`;
    91→};
    92→
    93→export const formatToCurrencyActivities = (
    94→  value: number | undefined,
    95→  currencyCode = 'BRL'
    96→): string => {
    97→  if (typeof value === 'undefined') return `R$ 0,00`;
    98→
    99→  const options = {
   100→    style: 'currency',
   101→    currency: currencyCode,
   102→    minimumFractionDigits: 2,
   103→    maximumFractionDigits: 3,
   104→  };
   105→
   106→  const formatNumber = new Intl.NumberFormat('pt-BR', options);
   107→
   108→  return formatNumber.format(value);
   109→};
   110→
   111→export const getActivityDescription = (activity: ActivityResponseData): string | undefined => {
   112→  return activity?.NumeroParcelas > 0 ? `Parcelado em ${activity?.NumeroParcelas}x` : undefined;
   113→};
   114→
   115→export const getActivityIconography = (
   116→  activity: ActivityResponseData,
   117→  customerCard: string
   118→): {
   119→  name: PropsIconsNameCore;
   120→  color: string;
   121→  titleColor?: string;
   122→  valueColor?: string;
   123→  descriptionColor?: string;
   124→} => {
   125→  const isPaymentOrCashback =
   126→    activity?.CodigoTransacao === 8003 ||
   127→    activity?.CodigoTransacao === 8306 ||
   128→    activity?.CodigoTransacao === 8019 ||
   129→    activity?.CodigoTransacao === 8356;
   130→
   131→  if (isPaymentOrCashback) {
   132→    const nameIcon: Record<number, PropsIconsNameCore> = {
   133→      8003: 'icon-circle-check',
   134→      8306: 'icon-cashback',
   135→      8019: 'icon-circle-check',
   136→      8356: 'icon-cashback',
   137→    };
   138→
   139→    return {
   140→      name: nameIcon?.[activity?.CodigoTransacao] ?? 'icon-cashback',
   141→      color: theme.colors.PLUS_COLOR_02,
   142→      titleColor: theme.colors.PLUS_COLOR_02,
   143→      valueColor: theme.colors.PLUS_COLOR_02,
   144→      descriptionColor: theme.colors.PLUS_COLOR_02,
   145→    };
   146→  }
   147→
   148→  // Estorno
   149→  if (activity?.CodigoTransacao === 8324) {
   150→    return {
   151→      name: 'icon-corner-up-left',
   152→      color: theme.colors.BRAND_COMPLEMENT_01,
   153→    };
   154→  }
   155→
   156→  if (/reversao|reversão|estorno/i.test(activity?.Descricao)) {
   157→    return {
   158→      name: 'icon-corner-up-left',
   159→      color: theme.colors.BRAND_COMPLEMENT_01,
   160→    };
   161→  }
   162→
   163→  // Outros lançamentos (mesalidade)
   164→  if (/mensalidade/i.test(activity?.Descricao)) {
   165→    return {
   166→      name: 'icon-money',
   167→      color: theme.colors.BRAND_COMPLEMENT_01,
   168→    };
   169→  }
   170→
   171→  // Compras no cartão (físico e virtual) não lançadas na fatura
   172→  if (activity?.Tipo === 'R' && activity?.Sequencia < 0) {
   173→    return { name: 'icon-card-check', color: theme.colors.BRAND_COMPLEMENT_01 };
   174→  }
   175→
   176→  const onUsPaymentType = activity?.NumeroCartao?.endsWith(customerCard?.slice(-4));
